mapper.select:
select d.id as doc_id, d.kb_id, kb.name as kb_name, d.file_name as original_name, case when pv.version_no is not null then 'PENDING_REVIEW' else d.document_status end as status, (select count(1) from km_document_chunk c where c.doc_id = d.id and (c.is_active = 1 or c.version_no = pv.version_no)) as chunk_count, concat('user-', coalesce(d.user_id, 0)) as uploader_name, d.created_at from km_document d left join km_knowledge_base kb on d.kb_id = kb.id left join km_document_version pv on pv.doc_id = d.id and pv.version_status = 'PENDING_REVIEW' where (d.document_status = 'PENDING_REVIEW' or pv.version_no is not null) and d.is_deleted = 0
and d.kb_id = #{kbId}
order by d.created_at desc limit #{offset}, #{pageSize}
